On a road trip, you travel $55$ miles every hour.

\textbf{Part A} Select an equation to represent the relationship.

\begin{enumerate}
\item[a.] $y = x + 55$
\item[b.] $y = 55x$
\item[c.] $y = x - 55$
\item[d.] $y = 5(5x)$
\end{enumerate}

\textbf{Part B} Use the equation to complete the table.

\begin{tikzpicture}
\draw (0,0) rectangle (5,3.5);
\draw (0,3) -- (5,3);
\draw (2.5,0) -- (2.5,3.5);
\node at (1.25,3.25) {\textbf{Time (hours)}};
\node at (3.75,3.25) {\textbf{Distance (miles)}};
\draw (0,2.4) -- (5,2.4);
\draw (0,1.8) -- (5,1.8);
\draw (0,1.2) -- (5,1.2);
\draw (0,0.6) -- (5,0.6);
\node at (1.25,2.7) {1};
\node at (1.25,2.1) {2};
\node at (1.25,1.5) {3};
\node at (1.25,0.9) {4};
\node at (1.25,0.3) {5};
\end{tikzpicture}
